mapper.delete:
DELETE FROM message_reactions
 WHERE message_id = #{messageId}
   AND user_id    = #{userId}
   AND emoji      = #{emoji}

mapper.select:
SELECT mr.message_id AS message_id, mr.emoji AS emoji, mr.user_id AS user_id, u.nickname AS user_nickname FROM message_reactions mr JOIN users u ON u.id = mr.user_id WHERE mr.message_id IN
#{id}
ORDER BY mr.message_id, mr.emoji, mr.created_at
